package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.bind.MapTypeAdapterFactory;
import com.google.gson.internal.ObjectConstructor;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentMatchers;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import java.lang.reflect.Type;
import java.util.HashMap;
import java.util.Map;

public class MapTypeAdapterFactoryTest {

  @Mock
  private ConstructorConstructor constructorConstructor;

  @Mock
  private Gson gson;

  @Mock
  private ObjectConstructor<HashMap<?, ?>> objectConstructor;

  @BeforeEach
  public void setUp() {
    MockitoAnnotations.openMocks(this);
  }

  @Test
  public void create_shouldReturnNullIfNotMap() {
    MapTypeAdapterFactory factory = new MapTypeAdapterFactory(constructorConstructor, false);
    TypeToken<String> stringTypeToken = TypeToken.get(String.class);

    TypeAdapter<String> adapter = factory.create(gson, stringTypeToken);

    assertNull(adapter);
  }

  @Test
  public void create_shouldReturnAdapterForMap() {
    MapTypeAdapterFactory factory = new MapTypeAdapterFactory(constructorConstructor, false);
    TypeToken<HashMap<String, Integer>> mapTypeToken = new TypeToken<HashMap<String, Integer>>() {};

    // Mock getMapKeyAndValueTypes static method using reflection proxy (simulate behavior)
    // Since $Gson$Types.getMapKeyAndValueTypes is static and final, we cannot mock it easily.
    // Instead, we rely on the real method behavior by using real TypeToken with HashMap<String, Integer>.

    // Mock key adapter returned by getKeyAdapter (private method) via reflection
    // We will spy on factory to mock getKeyAdapter
    MapTypeAdapterFactory spyFactory = spy(factory);

    Type keyType = String.class;
    TypeAdapter<String> keyAdapter = mock(TypeAdapter.class);
    doReturn(keyAdapter).when(spyFactory).getKeyAdapter(eq(gson), eq(keyType));

    // Mock value adapter returned by gson.getAdapter
    TypeAdapter<Integer> valueAdapter = mock(TypeAdapter.class);
    when(gson.getAdapter(ArgumentMatchers.<TypeToken<Integer>>any())).thenReturn(valueAdapter);

    // Mock constructorConstructor.get to return objectConstructor
    when(constructorConstructor.get(mapTypeToken)).thenReturn(objectConstructor);

    TypeAdapter<HashMap<String, Integer>> adapter = spyFactory.create(gson, mapTypeToken);

    assertNotNull(adapter);
    // The returned adapter class is MapTypeAdapterFactory.Adapter
    assertEquals("com.google.gson.internal.bind.MapTypeAdapterFactory$Adapter", adapter.getClass().getName());
  }
}
